def reverse_words_preserving_spaces(s: str) -> str:
    if not s:
        return ""

    words = []
    current_word = []
    for char in s:
        if char == ' ':
            if current_word:
                words.append("".join(current_word))
                current_word = []
        else:
            current_word.append(char)
    if current_word:
        words.append("".join(current_word))

    reversed_words = words[::-1]
    result = []
    word_index = 0
    for char in s:
        if char == ' ':
            result.append(' ')
        else:
            if word_index < len(reversed_words):
                result.append(reversed_words[word_index])
                word_index += 1
            else:
                # This case should ideally not be reached if logic is correct,
                # but as a fallback, we could append an empty string or original char
                # based on specific edge case interpretation.
                # For this problem, it implies a mismatch in word counting,
                # but given the problem constraints, it's safer to ensure
                # we don't go out of bounds.
                pass # This branch implies an error in logic if words are always replaced

    # Reconstruct the string by placing reversed words back into their original positions
    # while preserving spaces.
    # A more robust approach might be to iterate through the original string
    # and fill in the words.

    final_result_chars = list(s)
    current_word_start = -1
    word_count = 0

    for i, char in enumerate(s):
        if char != ' ':
            if current_word_start == -1:
                current_word_start = i
        else:
            if current_word_start != -1:
                # A word just ended
                word_length = i - current_word_start
                if word_count < len(reversed_words):
                    reversed_word = reversed_words[word_count]
                    for j in range(word_length):
                        if j < len(reversed_word):
                            final_result_chars[current_word_start + j] = reversed_word[j]
                        else:
                            # If reversed word is shorter, fill remaining with spaces or original char
                            # Based on problem, words are replaced, so shorter word means padding with original char
                            # or just stopping. The problem implies exact replacement.
                            # For now, assume words are replaced entirely.
                            pass
                word_count += 1
                current_word_start = -1

    # Handle the last word if the string doesn't end with a space
    if current_word_start != -1:
        word_length = len(s) - current_word_start
        if word_count < len(reversed_words):
            reversed_word = reversed_words[word_count]
            for j in range(word_length):
                if j < len(reversed_word):
                    final_result_chars[current_word_start + j] = reversed_word[j]
                else:
                    pass # Same logic as above

    return "".join(final_result_chars)

def run_length_encoding(s: str) -> str:
    if not s:
        return ""

    encoded_string = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i - 1]:
            count += 1
        else:
            encoded_string.append(str(count))
            encoded_string.append(s[i - 1])
            count = 1
    encoded_string.append(str(count))
    encoded_string.append(s[-1])

    return "".join(encoded_string)

def is_match(s: str, p: str) -> bool:
    memo = {}

    def dp(i, j):
        if (i, j) in memo:
            return memo[(i, j)]

        if j == len(p):
            return i == len(s)

        first_match = (i < len(s) and
                       (p[j] == s[i] or p[j] == '.'))

        if j + 1 < len(p) and p[j + 1] == '*':
            # Case 1: '*' matches zero occurrences of the preceding element
            # Case 2: '*' matches one or more occurrences of the preceding element
            result = dp(i, j + 2) or (first_match and dp(i + 1, j))
        else:
            result = first_match and dp(i + 1, j + 1)

        memo[(i, j)] = result
        return result

    return dp(0, 0)

import itertools

def string_permutations_unique(s: str) -> list[str]:
    return list(set(itertools.permutations(s)))

def roman_to_int(s: str) -> int:
    roman_map = {
        'I': 1, 'V': 5, '        X': 10, 'L': 50,
        'C': 100, 'D': 500, 'M': 1000
    }

    total = 0
    prev_value = 0

    for char in reversed(s):
        current_value = roman_map[char]

        if current_value < prev_value:
            total -= current_value
        else:
            total += current_value

        prev_value = current_value

    return total

def int_to_roman(num: int) -> str:
    if not (1 <= num <= 3999):
        raise ValueError("Input integer must be in the range 1 to 3999.")

    roman_map = {
        1000: 'M', 900: 'CM', 500: 'D', 400: 'CD',
        100: 'C', 90: 'XC', 50: 'L', 40: 'XL',
        10: 'X', 9: 'IX', 5: 'V', 4: 'IV', 1: 'I'
    }

    result = []
    for value, symbol in sorted(roman_map.items(), reverse=True):
        while num >= value:
            result.append(symbol)
            num -= value
    return "".join(result)

def caesar_cipher(text: str, shift: int, encode: bool) -> str:
    result = []
    if not encode:
        shift = -shift

    for char in text:
        if 'a' <= char <= 'z':
            start = ord('a')
            shifted_char = chr(((ord(char) - start + shift) % 26) + start)
            result.append(shifted_char)
        elif 'A' <= char <= 'Z':
            start = ord('A')
            shifted_char = chr(((ord(char) - start + shift) % 26) + start)
            result.append(shifted_char)
        else:
            result.append(char)
    return "".join(result)
